#!/usr/bin/env python3\nimport paramiko\nimport time\n\nHOST = "168.119.79.238"\nPORT = 77\nUSERNAME = "sanliur"\nPASSWORD = "CHANGE_ME_CWP_SSH_PASSWORD"\nDB_PASS = "CHANGE_ME_DB_PASSWORD"\n\ndef main():\n    ssh = paramiko.SSHClient()\n    ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())\n    ssh.connect(HOST, port=PORT, username=USERNAME, password=PASSWORD, \n                timeout=20, look_for_keys=False, allow_agent=False)\n    \n    channel = ssh.invoke_shell()\n    time.sleep(2)\n    \n    print("=== DATABASE DUZELTME ===\n")\n    \n    # 1. Export password\n    channel.send(f"export PGPASSWORD='{DB_PASS}'\n")\n    time.sleep(1)\n    \n    # 2. Create essential tables\n    sql = """\nCREATE TABLE IF NOT EXISTS users (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    email VARCHAR(255) UNIQUE NOT NULL,\n    password_hash VARCHAR(255) NOT NULL,\n    full_name VARCHAR(255),\n    username VARCHAR(50) UNIQUE,\n    bio TEXT,\n    avatar_url TEXT,\n    role VARCHAR(20) DEFAULT 'user' CHECK (role IN ('user', 'admin', 'moderator')),\n    points INTEGER DEFAULT 0,\n    level INTEGER DEFAULT 1,\n    is_banned BOOLEAN DEFAULT false,\n    email_verified BOOLEAN DEFAULT false,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS places (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    slug VARCHAR(255) UNIQUE NOT NULL,\n    name VARCHAR(255) NOT NULL,\n    description TEXT,\n    short_description TEXT,\n    address TEXT NOT NULL,\n    phone VARCHAR(50),\n    email VARCHAR(255),\n    website TEXT,\n    category VARCHAR(50) NOT NULL,\n    status VARCHAR(20) DEFAULT 'pending' CHECK (status IN ('active', 'pending', 'inactive')),\n    rating DECIMAL(2,1) DEFAULT 4.5,\n    review_count INTEGER DEFAULT 0,\n    is_featured BOOLEAN DEFAULT false,\n    is_verified BOOLEAN DEFAULT false,\n    price_range INTEGER DEFAULT 2 CHECK (price_range BETWEEN 1 AND 4),\n    amenities TEXT[],\n    tags TEXT[],\n    images TEXT[],\n    opening_hours JSONB,\n    latitude DECIMAL(10, 8),\n    longitude DECIMAL(11, 8),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS blog_posts (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    slug VARCHAR(255) UNIQUE NOT NULL,\n    title VARCHAR(255) NOT NULL,\n    excerpt TEXT,\n    content TEXT NOT NULL,\n    category VARCHAR(50) NOT NULL,\n    cover_image TEXT,\n    author_id UUID REFERENCES users(id),\n    tags TEXT[],\n    is_featured BOOLEAN DEFAULT false,\n    is_published BOOLEAN DEFAULT false,\n    published_at TIMESTAMP,\n    view_count INTEGER DEFAULT 0,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS events (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    slug VARCHAR(255) UNIQUE NOT NULL,\n    title VARCHAR(255) NOT NULL,\n    description TEXT,\n    location TEXT NOT NULL,\n    start_date DATE NOT NULL,\n    end_date DATE,\n    category VARCHAR(50),\n    image_url TEXT,\n    is_featured BOOLEAN DEFAULT false,\n    status VARCHAR(20) DEFAULT 'draft' CHECK (status IN ('published', 'draft', 'cancelled')),\n    created_by UUID REFERENCES users(id),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS historical_sites (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    slug VARCHAR(255) UNIQUE NOT NULL,\n    name VARCHAR(255) NOT NULL,\n    description TEXT,\n    short_description TEXT,\n    location TEXT NOT NULL,\n    period VARCHAR(100),\n    entry_fee VARCHAR(100),\n    opening_hours TEXT,\n    latitude DECIMAL(10, 8),\n    longitude DECIMAL(11, 8),\n    images TEXT[],\n    is_unesco BOOLEAN DEFAULT false,\n    is_featured BOOLEAN DEFAULT false,\n    status VARCHAR(20) DEFAULT 'active' CHECK (status IN ('active', 'draft', 'inactive')),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS reviews (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    place_id UUID REFERENCES places(id) ON DELETE CASCADE,\n    user_id UUID REFERENCES users(id) ON DELETE CASCADE,\n    rating INTEGER NOT NULL CHECK (rating BETWEEN 1 AND 5),\n    title VARCHAR(255),\n    content TEXT NOT NULL,\n    images TEXT[],\n    is_approved BOOLEAN DEFAULT false,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    UNIQUE(place_id, user_id)\n);\n\nCREATE TABLE IF NOT EXISTS favorites (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    place_id UUID REFERENCES places(id) ON DELETE CASCADE,\n    user_id UUID REFERENCES users(id) ON DELETE CASCADE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    UNIQUE(place_id, user_id)\n);\n\nINSERT INTO users (email, password_hash, full_name, role, email_verified)\nVALUES ('admin@sanliurfa.com', 'c75c1c5d23c4a30c22b8909b2947733cc538ff62e0da4b27d8589b93c1332866', 'Admin User', 'admin', true)\nON CONFLICT (email) DO NOTHING;\n\nSELECT 'Tables created successfully' as status;\n"""\n    \n    # Write SQL to file\n    channel.send("cat > /tmp/setup.sql << 'SQLEOF'\n")\n    time.sleep(1)\n    \n    for line in sql.strip().split('\n'):\n        channel.send(line + "\n")\n        time.sleep(0.1)\n    \n    channel.send("SQLEOF\n")\n    time.sleep(2)\n    \n    # Execute SQL\n    channel.send(f"psql -U sanliur_sanliurfa -d sanliur_sanliurfa -h localhost -f /tmp/setup.sql 2>&1\n")\n    time.sleep(5)\n    \n    output = ""\n    while channel.recv_ready():\n        output += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("DATABASE OUTPUT:")\n    print(output[-600:])\n    \n    # 3. Fix env file with correct format\n    channel.send("cd /home/sanliur/public_html\n")\n    time.sleep(1)\n    \n    env_content = f"""SITE_URL=https://sanliurfa.com\nNODE_ENV=production\nPORT=6000\nHOST=127.0.0.1\nDATABASE_URL=postgresql://sanliur_sanliurfa:{DB_PASS}@localhost:5432/sanliur_sanliurfa\nJWT_SECRET=change-this-secret-key-min-32-characters\n"""\n    \n    channel.send(f"cat > .env.production << 'ENVEOF'\n{env_content}ENVEOF\n")\n    time.sleep(2)\n    \n    # 4. Restart app\n    channel.send("source ~/.nvm/nvm.sh && pm2 restart sanliurfa\n")\n    time.sleep(5)\n    \n    output2 = ""\n    while channel.recv_ready():\n        output2 += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("\nRESTART OUTPUT:")\n    print(output2[-300:])\n    \n    channel.close()\n    ssh.close()\n\nif __name__ == "__main__":\n    main()\n
